export interface IHeatmapPoint {
  x: number;
  y: number;
  value: number;
}

export class HeatmapPlugin {
  private _max: number;
  private _points: IHeatmapPoint[];
  private _heatmapInstance: any;
  private _len: number;
  private _plane: Mesh;
  private _meshContainer: Object3D;
  private _divContainer: HTMLDivElement;
  private _currentWidth: number;
  private _currentHeight: number;
  private _box3: Box3;
  private _height = 1024;
  private _width = 1024;
  private _boundingBoxCenter = new Vector3();

  constructor(container: Object3D, target: Object3D) {
    this._meshContainer = container;
    this._max = 0;
    this._points = [];
    this.initPlugin();
    this.createPlane(target);
  }

  public initPlugin() {
    const container = (this._divContainer = document.createElement("div"));
    this._divContainer.style.width = `${this._width}px`;
    this._divContainer.style.height = `${this._height}px`;
    this._divContainer.style.display = "none";
    this._divContainer.className = "heatmap-container";
    document.body.appendChild(this._divContainer);

    this._heatmapInstance = h337.create({ container });
    this._heatmapInstance.setData({
      data: [],
      max: 0
    });
  }

  public createPlane(mainObj: Object3D) {
    if (!mainObj) {
      return console.warn("mainObj is null");
    }
    const canvasElement = this._heatmapInstance._renderer.canvas;
    this._box3 = new Box3();
    this._box3.setFromObject(mainObj);
    this._currentWidth = Math.abs(this._box3.max.x - this._box3.min.x);
    this._currentHeight = Math.abs(this._box3.max.y - this._box3.min.y);
    const len = (this._len = Math.max(this._currentWidth, this._currentHeight) * 2);

    const texture = new CanvasTexture(canvasElement);
    texture.flipY = false;
    const material = new MeshBasicMaterial({
      transparent: true,
      // side:DoubleSide,
      depthTest: false,
      depthWrite: false,
      map: texture
      // color: 0x00ff00
    });

    const planeGeometry = new PlaneBufferGeometry(len, len);
    this._plane = new Mesh(planeGeometry, material);
    this._box3.getCenter(this._plane.position);
    this._meshContainer.add(this._plane);
  }

  public setDatas(heatmapPoints: IHeatmapPoint[]) {
    if (!heatmapPoints || heatmapPoints.length === 0) {
      heatmapPoints = [];
      for (let i = 0; i < realData.length; i += 2) {
        heatmapPoints.push({ x: realData[i], y: realData[i + 1], value: 10 * Math.random() });
      }
    }
    this._points = [];
    heatmapPoints.forEach((v) => {
      if (v.value > this._max) {
        this._max = v.value;
      }
      this._box3.getCenter(this._boundingBoxCenter);
      this._points.push({
        value: v.value,
        x: ((v.x - this._boundingBoxCenter.x) / this._len + 0.5) * this._width,
        y: ((v.y - this._boundingBoxCenter.y) / this._len + 0.5) * this._height
      });
    });
    this._points.push({ x: 0, y: 0, value: 0 });

    this._heatmapInstance.setData({
      data: this._points,
      max: this._max,
      min: 0
    });
    (this._plane.material as MeshBasicMaterial).map.needsUpdate = true;
  }

  public setMax(value: number) {
    this._max = value || 0;
  }

  public visible(flag: boolean) {
    this._plane.visible = flag;
  }

  public dispose() {
    document.body.removeChild(this._divContainer);
    this._meshContainer.remove(this._plane);
    this._plane.geometry.dispose();
    (this._plane.material as MeshBasicMaterial).dispose();
  }
}
